# 输入获取
words = input().split(",")


# 算法入口
def getResult():
    ans = 0

    n = len(words)

    bits = [0] * n
    for i in range(n):
        for j in range(len(words[i])):
            bits[i] |= (1 << (ord(words[i][j]) - 97))

    for i in range(n):
        for j in range(i + 1, n):
            if (bits[i] & bits[j]) == 0:
                ans = max(ans, len(words[i]) * len(words[j]))

    return ans


# 算法调用
print(getResult())
